// Safe JSON parse of GPT-4o vision response
const rawContent = $json.message?.content || $json.choices?.[0]?.message?.content || '';

let parsed;
try {
  // Strip markdown code blocks if present
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  return [{ json: {
    parseError: true,
    errorMsg: `Could not parse AI response: ${e.message}`,
    rawContent,
    telegramId: $('Webhook Trigger').item.json.body.telegram_id,
    userId: $('Webhook Trigger').item.json.body.user_id
  } }];
}

// Validate confidence field
const validConfidence = ['high', 'medium', 'low'];
if (!validConfidence.includes(parsed.confidence)) {
  parsed.confidence = 'medium';
}

return [{ json: {
  parseError: false,
  foods: parsed.foods || [],
  estimatedCalories: parsed.estimated_calories || 0,
  proteinG: parsed.protein_g || 0,
  carbsG: parsed.carbs_g || 0,
  fatG: parsed.fat_g || 0,
  confidence: parsed.confidence,
  healthScore: parsed.health_score || 5,
  notes: parsed.notes || '',
  telegramId: $('Webhook Trigger').item.json.body.telegram_id,
  userId: $('Webhook Trigger').item.json.body.user_id,
  fileId: $('Webhook Trigger').item.json.body.file_id
} }];

