// Build the analysis result message
const analysis = $('Parse Vision Response').item.json;
const updatedLog = $('Update Daily Log Macros').item.json;
const user = await $postgres.query(
  'SELECT daily_calorie_target FROM users WHERE id = $1',
  [analysis.userId]
);
const target = user.rows[0]?.daily_calorie_target || 2000;
const totalToday = updatedLog.calories_consumed || analysis.estimatedCalories;
const remaining = target - totalToday;
const remainingText = remaining > 0
  ? `🟢 ${remaining} kcal remaining today`
  : `🔴 ${Math.abs(remaining)} kcal over target today`;

const healthStars = '⭐'.repeat(Math.min(Math.round(analysis.healthScore / 2), 5));

const foodList = (analysis.foods || []).map(f => `  • ${f}`).join('\n') || '  • Unknown items';

const message = `📸 <b>Food Analysis Result</b>\n\n` +
  `<b>Identified foods:</b>\n${foodList}\n\n` +
  `<b>Estimated nutrition:</b>\n` +
  `🔥 Calories: <b>${analysis.estimatedCalories} kcal</b>\n` +
  `🥩 Protein: ${analysis.proteinG}g | 🌾 Carbs: ${analysis.carbsG}g | 🥑 Fat: ${analysis.fatG}g\n\n` +
  `💡 ${analysis.notes}\n\n` +
  `📊 <b>Today's running total:</b> ${totalToday} kcal\n` +
  `${remainingText}\n\n` +
  `Confidence: ${healthStars} (${analysis.confidence})`;

return [{ json: { message, telegramId: analysis.telegramId, isLowConfidence: analysis.confidence === 'low' } }];
